from flask import Flask, request, jsonify
import logging

app = Flask(__name__)

# Configure logging
logging.basicConfig(filename='application.log', level=logging.INFO, format='%(asctime)s - %(message)s')

# Dummy user data for authentication
users = {
    "user1": {"password": "password1", "email": "user1@example.com"},
    "user2": {"password": "password2", "email": "user2@example.com"},
}

@app.route('/login', methods=['POST'])
def login():
    username = request.json.get('username')
    password = request.json.get('password')
    
    if username in users and users[username]['password'] == password:
        log_attempt(username, password, users[username]['email'])
        return jsonify({"message": "Login successful"}), 200
    else:
        log_attempt(username, password, None)
        return jsonify({"message": "Login failed"}), 401

def log_attempt(username, password, email):
    ip_address = request.remote_addr
    user_agent = request.headers.get('User-Agent')
    logging.info(f"Login attempt - Username: {username}, Password: {password}, Email: {email}, IP: {ip_address}, User-Agent: {user_agent}")

if __name__ == '__main__':
    app.run(debug=True)